SourceCode.Declaration:
/// <summary>
/// Item details import
/// </summary>
public class ETG_Acu_EcoResReleasedProdMasterDetailsImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResReleasedProdMasterDetailsImport  releasedProdImport;

    releasedProdImport = ETG_Acu_EcoResReleasedProdMasterDetailsImport::construct();

    if (releasedProdImport.prompt())
    {
        releasedProdImport.runOperation();
    }
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResReleasedProductV2Entity               releasedProd;
    ItemId                                      prodNum;

    DictEnum            dictProdSubTypeEnum = new DictEnum(enumNum(EcoResProductSubtype));
    DictEnum            dictEnumProdType = new DictEnum(enumNum(EcoResProductType));
    DictEnum            dictEnumPmfProdType = new DictEnum(enumNum(PmfProductType));
    DictEnum            dictEnumDefaultOrderType = new DictEnum(enumNum(ReqPOType));
    DictEnum            dictEnumFlushingPrinc = new DictEnum(enumNum(ProdFlushingPrincipItem));

    prodNum     = conpeek(_con, 1);

    select firstonly forupdate releasedProd
        where releasedProd.ItemNumber == prodNum;

    if (releasedProd)
    {
        releasedProd.ItemNumber                         = prodNum;
        releasedProd.BASESALESPRICESOURCE               = conpeek(_con, 2);
        releasedProd.BOMLEVEL                           = conpeek(_con, 3);
        releasedProd.BOMUNITSYMBOL                      = conpeek(_con, 4);
        //releasedProd.DEFAULTLEDGERDIMENSIONDISPLAYVALUE = conpeek(_con, 5);
        releasedProd.DEFAULTORDERTYPE                   = dictEnumDefaultOrderType.symbol2Value(conpeek(_con, 6));
        releasedProd.FLUSHINGPRINCIPLE                  = dictEnumFlushingPrinc.symbol2Value(conpeek(_con, 7));
        releasedProd.INVENTORYUNITSYMBOL                = conpeek(_con, 8);
        releasedProd.PRODUCTDIMENSIONGROUPNAME          = conpeek(_con, 9);
        releasedProd.PRODUCTGROUPID                     = conpeek(_con, 10);
        releasedProd.PRODUCTIONTYPE                     = dictEnumPmfProdType.symbol2Value(conpeek(_con, 11));
        releasedProd.PRODUCTNUMBER                      = conpeek(_con, 12);
        releasedProd.PRODUCTSUBTYPE                     = dictProdSubTypeEnum.symbol2Value(conpeek(_con, 13));
        releasedProd.PRODUCTTYPE                        = dictEnumProdType.symbol2Value(conpeek(_con, 14));
        releasedProd.PURCHASEPRICEDATE                  = conpeek(_con, 15);
        releasedProd.PURCHASEPRICEQUANTITY              = conpeek(_con, 16);
        releasedProd.PURCHASEUNITSYMBOL                 = conpeek(_con, 17);
        releasedProd.SALESPRICEDATE                     = conpeek(_con, 18);
        releasedProd.SALESPRICEQUANTITY                 = conpeek(_con, 19);
        releasedProd.SALESSALESTAXITEMGROUPCODE         = conpeek(_con, 20);
        releasedProd.SALESUNITSYMBOL                    = conpeek(_con, 21);
        releasedProd.SHELFADVICEPERIODDAYS              = conpeek(_con, 22);
        releasedProd.SHELFLIFEPERIODDAYS                = conpeek(_con, 23);
        releasedProd.STORAGEDIMENSIONGROUPNAME          = conpeek(_con, 24);
        releasedProd.TRACKINGDIMENSIONGROUPNAME         = conpeek(_con, 25);
        releasedProd.UNITCOSTDATE                       = conpeek(_con, 26);
        releasedProd.UNITCOSTQUANTITY                   = conpeek(_con, 27);

        // BusinessUnit (28)	Contract (29)	Department (30)	Intercompany (31)	Plant_Warehouse_Office (32)	Product_Service (33)	Trader_Employee (34)
        // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

        releasedProd.DEFAULTLEDGERDIMENSIONDISPLAYVALUE  = conPeek(_con, 32) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 30) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 34) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 33) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 31) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 29);
        releasedProd.update();
    } 
    else
    {
        throw Error (strFmt("@ETG_ENG_Labels:DMItemDetailsImpError"), prodNum);
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpItemDetails";

    return ret;
}
